INSERT INTO english_questions (path_id, topic_id, level, question, options, correct_answer, explanation, difficulty) VALUES

-- ============================================================================
-- SUBTOPIC 1: Action Verbs (24 questions)
-- ============================================================================

-- EASY (10 questions)
('foundation', 'verbs-basics', 'beginner', '"She _____ to school every day."', '["goes", "is", "seems", "becomes"]', 0, 'Action verb: shows action you can see/do. "goes" = physical action (movement). Pattern: subject + action verb.', 'easy'),

('foundation', 'verbs-basics', 'beginner', '"He _____ cricket on weekends."', '["plays", "looks", "feels", "appears"]', 0, 'Action verb: physical activity. "plays" = action you can do. Linking verbs: is, seems, feels (no action).', 'easy'),

('foundation', 'verbs-basics', 'beginner', '"They _____ delicious food."', '["eat", "are", "taste", "become"]', 0, 'Action verb: physical action. "eat" = action you do. "taste" can be linking (food tastes good) or action (I taste food).', 'easy'),

('foundation', 'verbs-basics', 'beginner', '"I _____ a book every night."', '["read", "am", "seem", "look"]', 0, 'Action verb: mental/physical action. "read" = action you do. am/seem/look = linking verbs (no action).', 'easy'),

('foundation', 'verbs-basics', 'beginner', '"She _____ her homework quickly."', '["finishes", "is", "becomes", "appears"]', 0, 'Action verb: activity you do. "finishes" = action (completing work). is/becomes/appears = linking verbs.', 'easy'),

('foundation', 'verbs-basics', 'beginner', 'Which is an action verb?', '["run", "is", "seem", "appear"]', 0, 'Action verbs: show action (run, jump, write, think). Linking verbs: connect subject to description (is, seem, appear).', 'easy'),

('foundation', 'verbs-basics', 'beginner', '"They _____ loudly in class."', '["talk", "are", "sound", "feel"]', 0, 'Action verb: activity you do. "talk" = action. "sound/feel" = linking verbs (describe state, no action).', 'easy'),

('foundation', 'verbs-basics', 'beginner', '"He _____ a letter to his friend."', '["writes", "is", "seems", "looks"]', 0, 'Action verb: physical action. "writes" = action you do. is/seems/looks = linking verbs.', 'easy'),

('foundation', 'verbs-basics', 'beginner', '"The dog _____ fast."', '["runs", "is", "appears", "becomes"]', 0, 'Action verb: physical movement. "runs" = action (movement). is/appears/becomes = linking verbs (state).', 'easy'),

('foundation', 'verbs-basics', 'beginner', 'Action verbs show:', '["what subject does", "what subject is", "how subject feels", "description of subject"]', 0, 'Action verbs: show action (physical/mental). Linking verbs: show state of being (what subject is/feels).', 'easy'),

-- MEDIUM (10 questions)
('foundation', 'verbs-basics', 'beginner', 'What is wrong? "She seems happy and jumps."', '["Both verbs correct", "Use: is instead of seems", "Use: looks instead of jumps", "Nothing wrong"]', 3, 'Both correct! "seems" (linking verb) + "jumps" (action verb). Sentence has both types. Pattern: linking + and + action.', 'medium'),

('foundation', 'verbs-basics', 'beginner', 'Choose the action verb: "The flowers smell sweet and bloom."', '["smell", "bloom", "Both", "Neither"]', 1, '"bloom" = action verb (flowers do it). "smell" = linking verb here (connects flowers to sweet). Context determines verb type!', 'medium'),

('foundation', 'verbs-basics', 'beginner', 'Error in: "He thinks the answer."', '["Use: knows instead of thinks", "Add: about after thinks", "Use: is instead of thinks", "Nothing wrong"]', 1, 'Action verb "think" needs preposition. Correct: "He thinks about the answer." Pattern: think about (not think + direct object alone).', 'medium'),

('foundation', 'verbs-basics', 'beginner', 'Arrange: every / exercises / She / morning / does', '["She does exercises every morning", "She is exercises every morning", "She seems exercises every morning", "She exercises every morning does"]', 0, 'Action verb: "does" (performs). Pattern: subject + action verb + object + time. Correct: "She does exercises every morning."', 'medium'),

('foundation', 'verbs-basics', 'beginner', 'Which sentence has TWO action verbs?', '["She runs and jumps", "She is tall and smart", "He seems tired but works", "The food tastes good"]', 0, 'Two action verbs: "runs" + "jumps" (both actions). Option C: "seems" (linking) + "works" (action) = mixed.', 'medium'),

('foundation', 'verbs-basics', 'beginner', 'What is the error? "The cake smells and tastes delicious."', '["Use: smelled instead of smells", "Use: tasted instead of tastes", "Use: is instead of smells", "Nothing wrong"]', 3, 'Both linking verbs! "smells delicious" (linking) + "tastes delicious" (linking). Both connect cake to description. Correct!', 'medium'),

('foundation', 'verbs-basics', 'beginner', 'Rearrange: homework / I / my / finish / always', '["I always finish my homework", "I always am my homework", "I finish always my homework", "I my homework always finish"]', 0, 'Action verb: "finish" (complete). Pattern: subject + adverb + action verb + object. Natural: "I always finish my homework."', 'medium'),

('foundation', 'verbs-basics', 'beginner', 'Choose: "She _____ the piano beautifully."', '["plays", "is", "seems", "sounds"]', 0, 'Action verb: physical activity. "plays" = action (performing). "sounds" = linking (She sounds beautiful = description).', 'medium'),

('foundation', 'verbs-basics', 'beginner', 'Error in: "He grows taller every year."', '["Use: becomes instead of grows", "Use: is instead of grows", "Use: gets instead of grows", "Nothing wrong"]', 3, '"grows" = linking verb here (becomes taller, not action). "grows" can be action (plants grow) or linking (person grows taller). Context correct!', 'medium'),

('foundation', 'verbs-basics', 'beginner', 'Which is NOT an action verb?', '["think", "write", "remain", "study"]', 2, '"remain" = linking verb (stay in a state). think/write/study = action verbs (activities you do).', 'medium'),

-- HARD (4 questions)
('foundation', 'verbs-basics', 'beginner', 'Which is WRONG?', '["The food tastes spicy", "She tastes the soup", "He feels sad", "She feels the fabric"]', 3, 'All correct! "tastes/feels" can be linking OR action. "tastes spicy" (linking), "tastes the soup" (action), "feels sad" (linking), "feels the fabric" (action). Context determines!', 'hard'),

('foundation', 'verbs-basics', 'beginner', 'Arrange: carefully / listened / the / to / teacher / Students', '["Students listened to the teacher carefully", "Students listened carefully to the teacher", "Both A and B correct", "Students carefully listened to the teacher"]', 2, 'Adverb placement: after verb + object OR before verb. Both natural: "listened...carefully" / "listened carefully..." Both correct!', 'hard'),

('foundation', 'verbs-basics', 'beginner', 'Error: "The milk smells badly."', '["Use: bad instead of badly", "Use: smelling instead of smells", "Use: is smelling instead of smells", "Nothing wrong"]', 0, '"smells" = linking verb (not action). Use adjective "bad" (not adverb "badly"). Correct: "The milk smells bad." Pattern: linking + adjective.', 'hard'),

('foundation', 'verbs-basics', 'beginner', 'Identify ALL action verbs: "She studies hard, looks tired, but remains focused."', '["studies only", "studies, looks", "studies, remains", "All three"]', 0, 'Action verb: "studies" only. "looks tired" (linking = appears tired). "remains focused" (linking = stays focused). Two linking, one action!', 'hard'),

-- ============================================================================
-- SUBTOPIC 2: Linking Verbs (24 questions)
-- ============================================================================

-- EASY (10 questions)
('foundation', 'verbs-basics', 'beginner', '"She _____ happy today."', '["is", "goes", "does", "makes"]', 0, 'Linking verb: connects subject to description. "is" links "she" to "happy." Pattern: subject + linking verb + adjective.', 'easy'),

('foundation', 'verbs-basics', 'beginner', '"The soup _____ delicious."', '["tastes", "eats", "cooks", "makes"]', 0, 'Linking verb: "tastes" connects soup to description (delicious). Not action here. Pattern: subject + linking verb + adjective.', 'easy'),

('foundation', 'verbs-basics', 'beginner', '"He _____ tired after work."', '["feels", "works", "goes", "does"]', 0, 'Linking verb: "feels" connects "he" to "tired." Describes state. Pattern: subject + linking verb + adjective.', 'easy'),

('foundation', 'verbs-basics', 'beginner', '"The flowers _____ beautiful."', '["look", "grow", "plant", "water"]', 0, 'Linking verb: "look" connects flowers to description (beautiful). Not action. Pattern: subject + linking verb + adjective.', 'easy'),

('foundation', 'verbs-basics', 'beginner', '"They _____ excited about the trip."', '["seem", "go", "plan", "book"]', 0, 'Linking verb: "seem" connects subject to description (excited). Pattern: subject + linking verb + adjective.', 'easy'),

('foundation', 'verbs-basics', 'beginner', 'Which is a linking verb?', '["appear", "run", "jump", "write"]', 0, 'Linking verbs: be (is/am/are), seem, appear, become, feel, look, taste, smell, sound, remain, grow, stay. Connect subject to description.', 'easy'),

('foundation', 'verbs-basics', 'beginner', '"The music _____ loud."', '["sounds", "plays", "makes", "sings"]', 0, 'Linking verb: "sounds" connects music to description (loud). Pattern: subject + linking verb + adjective.', 'easy'),

('foundation', 'verbs-basics', 'beginner', '"She _____ a doctor."', '["is", "does", "works", "studies"]', 0, 'Linking verb: "is" connects subject to noun (doctor). Pattern: subject + linking verb + noun (identity).', 'easy'),

('foundation', 'verbs-basics', 'beginner', '"He _____ calm during the exam."', '["remained", "wrote", "finished", "studied"]', 0, 'Linking verb: "remained" = stayed (state). Connects subject to description. Pattern: subject + linking verb + adjective.', 'easy'),

('foundation', 'verbs-basics', 'beginner', 'Linking verbs connect subject to:', '["description or identity", "action performed", "object received", "time of action"]', 0, 'Linking verbs: connect subject to adjective (description) OR noun (identity). No action shown. Pattern: subject = description.', 'easy'),

-- MEDIUM (10 questions)
('foundation', 'verbs-basics', 'beginner', 'What is wrong? "She is quickly."', '["Use: quick instead of quickly", "Use: goes instead of is", "Add: moving after quickly", "Both A and C"]', 3, 'Linking verb + adverb = wrong. Fix: "She is quick" (linking + adjective) OR "She moves quickly" (action + adverb). Both fixes work!', 'medium'),

('foundation', 'verbs-basics', 'beginner', 'Choose correct: "The story _____ interesting."', '["sounds", "tells", "writes", "speaks"]', 0, 'Linking verb: "sounds" connects story to description. Not action here. Pattern: subject + linking verb + adjective.', 'medium'),

('foundation', 'verbs-basics', 'beginner', 'Error in: "He became angrily."', '["Use: angry instead of angrily", "Use: became angry quickly", "Use: was instead of became", "Nothing wrong"]', 0, 'Linking verb + adjective (not adverb). "became" = linking verb. Correct: "He became angry." Pattern: linking verb + adjective.', 'medium'),

('foundation', 'verbs-basics', 'beginner', 'Arrange: very / She / confident / grew', '["She grew very confident", "She grew very confidently", "She very grew confident", "She confidently grew"]', 0, 'Linking verb + adjective. "grew" = linking (became). Pattern: subject + linking verb + adverb + adjective. Correct: "She grew very confident."', 'medium'),

('foundation', 'verbs-basics', 'beginner', 'Which sentence uses linking verb correctly?', '["The cake tastes sweetly", "The cake tastes sweet", "The cake tastes sweets", "The cake is tasting sweet"]', 1, 'Linking verb + adjective. Correct: "tastes sweet" (not sweetly). Linking verbs don''t use continuous form (*is tasting).', 'medium'),

('foundation', 'verbs-basics', 'beginner', 'What is the error? "The idea sounds greatly."', '["Use: great instead of greatly", "Use: sounds like greatly", "Use: is instead of sounds", "Nothing wrong"]', 0, 'Linking verb + adjective (not adverb). Correct: "The idea sounds great." Pattern: linking verb + adjective (not adverb).', 'medium'),

('foundation', 'verbs-basics', 'beginner', 'Rearrange: sick / feeling / I / am', '["I am feeling sick", "I am sick feeling", "I feeling am sick", "I am sickly feeling"]', 0, 'Linking verb: "am feeling" (continuous allowed with feel). Pattern: subject + am/is/are + feeling + adjective. Correct: "I am feeling sick."', 'medium'),

('foundation', 'verbs-basics', 'beginner', 'Choose: "After practice, he _____ stronger."', '["became", "made", "did", "went"]', 0, 'Linking verb: "became" = changed to (state). Pattern: subject + linking verb + adjective (comparative).', 'medium'),

('foundation', 'verbs-basics', 'beginner', 'Error in: "She looks beautifully in that dress."', '["Use: beautiful instead of beautifully", "Use: is looking instead of looks", "Remove: in that dress", "Nothing wrong"]', 0, 'Linking verb + adjective. "looks" = linking verb (appears). Correct: "She looks beautiful." Pattern: linking + adjective (not adverb).', 'medium'),

('foundation', 'verbs-basics', 'beginner', 'Which is a linking verb? "The plan fell through."', '["fell (linking)", "fell (action)", "through (verb)", "No verb"]', 1, '"fell" = action verb here (fell through = failed). "fell" can be linking ("fell silent" = became silent) but not here. Context matters!', 'medium'),

-- HARD (4 questions)
('foundation', 'verbs-basics', 'beginner', 'Which is WRONG?', '["She is happy", "He seems tired", "They appear busy", "We remain carefully"]', 3, 'Linking verb + adjective (not adverb). Wrong: "remain carefully." Correct: "remain careful." Pattern: linking + adjective always.', 'hard'),

('foundation', 'verbs-basics', 'beginner', 'Arrange: during / stayed / the / calm / exam / He', '["He stayed calm during the exam", "He stayed calmly during the exam", "He calmly stayed during the exam", "Both A and B"]', 0, 'Linking verb + adjective. "stayed" = linking (remained). Correct: "stayed calm" (not calmly). Pattern: linking + adjective.', 'hard'),

('foundation', 'verbs-basics', 'beginner', 'Error: "The bread smells freshly baked."', '["Use: fresh instead of freshly", "Use: is smelling instead of smells", "Remove: baked", "Nothing wrong"]', 3, 'Actually correct! "freshly" modifies "baked" (adverb + past participle), not "smells." Pattern: smells + adverb + past participle. "freshly baked" = compound adjective!', 'hard'),

('foundation', 'verbs-basics', 'beginner', 'Identify ALL linking verbs: "She is smart, looks confident, and works hard."', '["is only", "is, looks", "is, looks, works", "All three"]', 1, 'Linking verbs: "is smart" (linking) + "looks confident" (linking). "works hard" = action verb + adverb. Two linking, one action!', 'hard'),

-- ============================================================================
-- SUBTOPIC 3: Helping (Auxiliary) Verbs (24 questions)
-- ============================================================================

-- EASY (10 questions)
('foundation', 'verbs-basics', 'beginner', '"She _____ going to school."', '["is", "goes", "go", "went"]', 0, 'Helping verb: "is" helps main verb "going." Pattern: helping verb (is/am/are) + main verb-ing.', 'easy'),

('foundation', 'verbs-basics', 'beginner', '"They _____ playing cricket."', '["are", "play", "plays", "played"]', 0, 'Helping verb: "are" helps main verb "playing." Pattern: helping verb + main verb-ing (present continuous).', 'easy'),

('foundation', 'verbs-basics', 'beginner', '"He _____ eaten lunch."', '["has", "eat", "eats", "eating"]', 0, 'Helping verb: "has" helps main verb "eaten." Pattern: helping verb (has/have) + past participle (present perfect).', 'easy'),

('foundation', 'verbs-basics', 'beginner', '"I _____ completed my work."', '["have", "complete", "completes", "completing"]', 0, 'Helping verb: "have" helps main verb "completed." Pattern: have/has + past participle.', 'easy'),

('foundation', 'verbs-basics', 'beginner', '"She _____ not like coffee."', '["does", "do", "is", "are"]', 0, 'Helping verb: "does" helps form negative. Pattern: does + not + base verb (simple present negative).', 'easy'),

('foundation', 'verbs-basics', 'beginner', 'Which is a helping verb?', '["is", "run", "happy", "quickly"]', 0, 'Helping verbs: be (is/am/are/was/were), have (has/have/had), do (do/does/did). Help main verbs form tenses.', 'easy'),

('foundation', 'verbs-basics', 'beginner', '"_____ you like ice cream?"', '["Do", "Are", "Is", "Does"]', 0, 'Helping verb: "Do" forms question. Pattern: Do/Does + subject + base verb? (simple present question).', 'easy'),

('foundation', 'verbs-basics', 'beginner', '"We _____ been waiting for hours."', '["have", "are", "do", "did"]', 0, 'Helping verb: "have" helps form present perfect continuous. Pattern: have/has + been + verb-ing.', 'easy'),

('foundation', 'verbs-basics', 'beginner', '"He _____ studying yesterday."', '["was", "is", "has", "did"]', 0, 'Helping verb: "was" helps main verb "studying." Pattern: was/were + verb-ing (past continuous).', 'easy'),

('foundation', 'verbs-basics', 'beginner', 'Helping verbs help:', '["form tenses and questions", "show action only", "describe subject", "replace main verb"]', 0, 'Helping verbs: help main verbs form tenses (is going, has gone), questions (Do you?), negatives (does not). Never stand alone!', 'easy'),

-- MEDIUM (10 questions)
('foundation', 'verbs-basics', 'beginner', 'What is wrong? "She is go to school."', '["Use: going instead of go", "Use: goes instead of go", "Remove: is", "Both A works"]', 0, 'Helping verb "is" needs verb-ing (not base form). Correct: "She is going to school." Pattern: is/am/are + verb-ing.', 'medium'),

('foundation', 'verbs-basics', 'beginner', 'Choose correct: "_____ he finished his homework?"', '["Has", "Does", "Is", "Do"]', 0, 'Present perfect question: Has/Have + subject + past participle? Correct: "Has he finished?" Pattern: helping verb + subject + main verb.', 'medium'),

('foundation', 'verbs-basics', 'beginner', 'Error in: "They have went home."', '["Use: gone instead of went", "Use: go instead of went", "Use: are instead of have", "Nothing wrong"]', 0, 'Present perfect: have/has + past participle (not simple past). Correct: "They have gone home." gone = past participle, went = simple past.', 'medium'),

('foundation', 'verbs-basics', 'beginner', 'Arrange: homework / not / I / done / have / my', '["I have not done my homework", "I not have done my homework", "I have done not my homework", "I have my homework not done"]', 0, 'Negative: have/has + not + past participle. Pattern: subject + helping verb + not + main verb. Correct word order!', 'medium'),

('foundation', 'verbs-basics', 'beginner', 'Which is correct?', '["He is play cricket", "He is playing cricket", "He is plays cricket", "He playing cricket"]', 1, 'Present continuous: is/am/are + verb-ing. Correct: "He is playing cricket." Helping verb + main verb-ing.', 'medium'),

('foundation', 'verbs-basics', 'beginner', 'What is the error? "She does goes to school."', '["Remove: does OR use: go", "Use: is instead of does", "Use: going instead of goes", "Both A works"]', 3, 'Double present tense = wrong. Fix: "She goes" (no does) OR "She does go" (emphasis, correct!). "does goes" = wrong. Remove one!', 'medium'),

('foundation', 'verbs-basics', 'beginner', 'Rearrange: been / They / waiting / have / long / for', '["They have been waiting for long", "They been have waiting for long", "They have waiting been for long", "They waiting have been for long"]', 0, 'Present perfect continuous: have/has + been + verb-ing. Pattern: subject + have + been + verb-ing. Correct order!', 'medium'),

('foundation', 'verbs-basics', 'beginner', 'Choose: "I _____ not understand this."', '["do", "am", "have", "is"]', 0, 'Simple present negative: do/does + not + base verb. Correct: "I do not understand." Pattern: do + not + verb.', 'medium'),

('foundation', 'verbs-basics', 'beginner', 'Error in: "We was playing football."', '["Use: were instead of was", "Use: are instead of was", "Use: played instead of playing", "Nothing wrong"]', 0, 'Plural subject (we) = were (not was). Correct: "We were playing football." was = singular (I, he, she, it).', 'medium'),

('foundation', 'verbs-basics', 'beginner', 'Which needs helping verb? "She _____ to school every day."', '["goes (no helper)", "is going (helper: is)", "Both correct", "Neither correct"]', 2, 'Both correct! "She goes" (simple present, no helper). "She is going" (continuous, helper: is). Context determines!', 'medium'),

-- HARD (4 questions)
('foundation', 'verbs-basics', 'beginner', 'Which is WRONG?', '["I am reading", "She has finished", "They were playing", "He have gone"]', 3, 'Subject-verb agreement: "He" (singular) = has (not have). Correct: "He has gone." have = plural (I, you, we, they).', 'hard'),

('foundation', 'verbs-basics', 'beginner', 'Arrange: question / you / Did / the / understand', '["Did you understand the question", "Did you understood the question", "You did understand the question", "Both A and C"]', 0, 'Question form: Did + subject + base verb (not past tense). Correct: "Did you understand?" NOT "Did you understood."', 'hard'),

('foundation', 'verbs-basics', 'beginner', 'Error: "She has been went to the market."', '["Use: gone instead of went", "Remove: been", "Use: going instead of went", "Both A and C work"]', 3, 'Two fixes: "She has gone" (present perfect) OR "She has been going" (present perfect continuous). "been went" = wrong combination!', 'hard'),

('foundation', 'verbs-basics', 'beginner', 'Identify helping verbs: "I have been working here since 2020 and am enjoying it."', '["have, been, am", "have, been", "have, am", "been, am"]', 0, 'Three helping verbs: "have" (helps been), "been" (helps working), "am" (helps enjoying). working/enjoying = main verbs.', 'hard'),

-- ============================================================================
-- SUBTOPIC 4: Modal Verbs (24 questions)
-- ============================================================================

-- EASY (10 questions)
('foundation', 'verbs-basics', 'beginner', '"I _____ speak English."', '["can", "cans", "canning", "could"]', 0, 'Modal verb: "can" shows ability. Always use base form (no -s, no -ing). Pattern: subject + modal + base verb.', 'easy'),

('foundation', 'verbs-basics', 'beginner', '"She _____ come tomorrow."', '["will", "wills", "willing", "willed"]', 0, 'Modal verb: "will" shows future. No -s, no -ing. Pattern: subject + modal + base verb.', 'easy'),

('foundation', 'verbs-basics', 'beginner', '"You _____ study hard."', '["should", "shoulds", "shoulding", "shall"]', 0, 'Modal verb: "should" shows advice. No -s, no -ing. Pattern: subject + modal + base verb.', 'easy'),

('foundation', 'verbs-basics', 'beginner', '"They _____ finish on time."', '["must", "musts", "musting", "have to"]', 0, 'Modal verb: "must" shows necessity. No -s, no -ing. Pattern: subject + modal + base verb.', 'easy'),

('foundation', 'verbs-basics', 'beginner', '"_____ I help you?"', '["May", "Mays", "Maying", "Am"]', 0, 'Modal verb: "May" shows permission/polite request. No -s, no -ing. Pattern: Modal + subject + base verb?', 'easy'),

('foundation', 'verbs-basics', 'beginner', 'Which is a modal verb?', '["can", "is", "have", "do"]', 0, 'Modal verbs: can, could, will, would, shall, should, may, might, must. Express ability, permission, possibility, advice.', 'easy'),

('foundation', 'verbs-basics', 'beginner', '"He _____ be late today."', '["might", "mights", "mighting", "is might"]', 0, 'Modal verb: "might" shows possibility. No -s, no -ing, no helping verb before it. Pattern: subject + modal + be/verb.', 'easy'),

('foundation', 'verbs-basics', 'beginner', '"We _____ leave now."', '["should", "shoulds", "should to", "are should"]', 0, 'Modal verb: "should" shows advice. No -s, no to, no helping verb. Pattern: subject + modal + base verb.', 'easy'),

('foundation', 'verbs-basics', 'beginner', '"_____ you swim?"', '["Can", "Do can", "Are can", "Cans"]', 0, 'Modal verb forms question by inversion. Pattern: Modal + subject + base verb? No helping verb (do) needed!', 'easy'),

('foundation', 'verbs-basics', 'beginner', 'After modal verbs, use:', '["base form (no to)", "to + base form", "verb-ing", "past tense"]', 0, 'Rule: modal + base verb (no to, no -ing, no -ed). Pattern: I can go (NOT can to go, can going, can went).', 'easy'),

-- MEDIUM (10 questions)
('foundation', 'verbs-basics', 'beginner', 'What is wrong? "She cans speak French."', '["Use: can instead of cans", "Use: is can instead of cans", "Use: could instead of cans", "Nothing wrong"]', 0, 'Modal verbs never add -s! Correct: "She can speak French." Pattern: modal (no -s) + base verb.', 'medium'),

('foundation', 'verbs-basics', 'beginner', 'Choose correct: "You _____ to listen carefully."', '["must (no to)", "must to", "should to", "have"]', 0, 'Modal + base verb (no to). Correct: "You must listen" (NOT must to listen). Pattern: modal + base form.', 'medium'),

('foundation', 'verbs-basics', 'beginner', 'Error in: "He should to study more."', '["Remove: to", "Use: studies instead of study", "Use: studying instead of study", "Nothing wrong"]', 0, 'Modal + base verb (no to). Correct: "He should study more." Pattern: should + base (NOT should to).', 'medium'),

('foundation', 'verbs-basics', 'beginner', 'Arrange: finish / We / must / project / the / today', '["We must finish the project today", "We must to finish the project today", "We must finishing the project today", "We musts finish the project today"]', 0, 'Modal + base verb (no -s, no to, no -ing). Pattern: subject + modal + base verb + object. Correct form!', 'medium'),

('foundation', 'verbs-basics', 'beginner', 'Which is correct?', '["She can plays piano", "She can play piano", "She can playing piano", "She cans play piano"]', 1, 'Modal + base verb (no -s, no -ing). Correct: "She can play piano." Pattern: can + base form.', 'medium'),

('foundation', 'verbs-basics', 'beginner', 'What is the error? "They will going tomorrow."', '["Use: go instead of going", "Use: will go tomorrow", "Remove: will", "Both A and B"]', 3, 'Modal + base verb (not -ing). Correct: "They will go tomorrow." Pattern: will + base (NOT will + -ing).', 'medium'),

('foundation', 'verbs-basics', 'beginner', 'Rearrange: careful / You / be / should / more', '["You should be more careful", "You should to be more careful", "You should being more careful", "You shoulds be more careful"]', 0, 'Modal + base verb. "be" = base form. Pattern: subject + modal + be + adjective. Correct: "You should be more careful."', 'medium'),

('foundation', 'verbs-basics', 'beginner', 'Choose: "_____ we start the meeting?"', '["Shall", "Do shall", "Shalls", "Are shall"]', 0, 'Modal forms question by inversion (no do). Pattern: Modal + subject + base verb? Correct: "Shall we start?"', 'medium'),

('foundation', 'verbs-basics', 'beginner', 'Error in: "She might can help you."', '["Use: might help (remove: can)", "Use: can help (remove: might)", "Use: might be able to help", "All corrections work"]', 3, 'Two modals = wrong! Fix: "She might help" OR "She can help" OR "might be able to help." Never: modal + modal!', 'medium'),

('foundation', 'verbs-basics', 'beginner', 'Which expresses ability?', '["can / could", "will / would", "must", "should"]', 0, 'Ability: can (present), could (past). will/would = future/polite. must = necessity. should = advice.', 'medium'),

-- HARD (4 questions)
('foundation', 'verbs-basics', 'beginner', 'Which is WRONG?', '["You must finish", "She can swim", "He should to go", "They will arrive"]', 2, 'Modal + base (no to). Wrong: "should to go." Correct: "should go." Pattern: modal + base verb only.', 'hard'),

('foundation', 'verbs-basics', 'beginner', 'Arrange: I / able / speak / was / English / to', '["I was able to speak English", "I could to speak English", "I was can speak English", "Both A and B"]', 0, 'Past ability: "could" OR "was able to." Correct: "I was able to speak English." Note: "be able to" = NOT a modal (needs "to")!', 'hard'),

('foundation', 'verbs-basics', 'beginner', 'Error: "You must not to enter here."', '["Remove: to", "Use: should instead of must", "Use: entering instead of enter", "Nothing wrong"]', 0, 'Modal + base (no to). Correct: "You must not enter here." Pattern: modal + not + base (NO to).', 'hard'),

('foundation', 'verbs-basics', 'beginner', 'Identify ALL modals: "I can swim, but I could not swim last year, so I should practice more."', '["can, could, should", "can, should", "could, should", "can only"]', 0, 'Three modals: "can" (present ability), "could" (past ability), "should" (advice). All express different meanings!', 'hard'),

-- ============================================================================
-- SUBTOPIC 5: Main vs Helping Verbs (24 questions)
-- ============================================================================

-- EASY (10 questions)
('foundation', 'verbs-basics', 'beginner', 'In "She is reading," which is the main verb?', '["reading", "is", "Both", "Neither"]', 0, 'Main verb: shows main action/state. "reading" = main verb (action). "is" = helping verb (forms continuous).', 'easy'),

('foundation', 'verbs-basics', 'beginner', 'In "They have finished," which is the helping verb?', '["have", "finished", "Both", "Neither"]', 0, 'Helping verb: helps form tense. "have" = helping verb. "finished" = main verb (action completed).', 'easy'),

('foundation', 'verbs-basics', 'beginner', 'In "I can swim," which is the main verb?', '["swim", "can", "Both", "Neither"]', 0, 'Main verb: shows action. "swim" = main verb. "can" = modal (type of helping verb, shows ability).', 'easy'),

('foundation', 'verbs-basics', 'beginner', 'How many verbs? "She is playing cricket."', '["2 (is, playing)", "1 (playing)", "3", "0"]', 0, 'Two verbs: "is" (helping verb) + "playing" (main verb). Together form present continuous tense.', 'easy'),

('foundation', 'verbs-basics', 'beginner', '"He runs fast." Main verb?', '["runs", "fast", "He", "No main verb"]', 0, 'Main verb: "runs" (action). No helping verb here. Simple present = main verb alone.', 'easy'),

('foundation', 'verbs-basics', 'beginner', 'Main verb always shows:', '["main action or state", "time of action only", "subject only", "nothing"]', 0, 'Main verb: shows main action (run, eat) or state (is, seem). Helping verbs: assist main verb with tense/mood.', 'easy'),

('foundation', 'verbs-basics', 'beginner', 'In "We will go," which is helping verb?', '["will", "go", "Both", "Neither"]', 0, 'Helping verb: "will" (modal, shows future). "go" = main verb (action). Pattern: helping + main.', 'easy'),

('foundation', 'verbs-basics', 'beginner', '"She sings." Has helping verb?', '["No", "Yes (sings)", "Yes (She)", "Yes (implied)"]', 0, 'No helping verb! Simple present = main verb alone. "sings" = main verb only. Pattern: subject + main verb.', 'easy'),

('foundation', 'verbs-basics', 'beginner', 'In "They are happy," main verb?', '["are", "happy", "They", "No main verb"]', 0, 'Main verb: "are" (linking verb, shows state). No helping verb. "happy" = adjective (describes subject).', 'easy'),

('foundation', 'verbs-basics', 'beginner', 'Helping verbs include:', '["be, have, do, modals", "action verbs", "adjectives", "adverbs"]', 0, 'Helping verbs: be (is/am/are), have (has/have), do (do/does/did), modals (can/will/should). Help form tenses.', 'easy'),

-- MEDIUM (10 questions)
('foundation', 'verbs-basics', 'beginner', 'What is wrong? "She reading a book."', '["Add: is before reading", "Use: reads instead of reading", "Add: are before reading", "Both A and B"]', 3, 'Missing helping verb OR wrong form. Fix: "She is reading" (helping + main) OR "She reads" (main only). Both correct!', 'medium'),

('foundation', 'verbs-basics', 'beginner', 'In "I have been waiting," how many verbs?', '["3 (have, been, waiting)", "2 (have, waiting)", "1 (waiting)", "4"]', 0, 'Three verbs: "have" (helping) + "been" (helping) + "waiting" (main). Present perfect continuous needs multiple helpers!', 'medium'),

('foundation', 'verbs-basics', 'beginner', 'Error in: "He do goes to school."', '["Remove: do OR use: go", "Use: does instead of do", "Remove: to", "Multiple issues"]', 3, 'Multiple errors! "do goes" = double present. Fix: "He goes" OR "He does go" (emphasis). Never: do + goes together!', 'medium'),

('foundation', 'verbs-basics', 'beginner', 'Arrange: finished / have / their / They / homework', '["They have finished their homework", "They finished have their homework", "They have their homework finished", "They homework have finished"]', 0, 'Pattern: subject + helping verb + main verb + object. Correct: "They have finished their homework." Standard word order!', 'medium'),

('foundation', 'verbs-basics', 'beginner', 'Which sentence has NO helping verb?', '["She is running", "They have gone", "I can swim", "He plays cricket"]', 3, 'Simple present/past = no helping verb. "He plays" = main verb only. Others: is (helping), have (helping), can (modal).', 'medium'),

('foundation', 'verbs-basics', 'beginner', 'In "We should be leaving," identify verbs:', '["should (modal), be (helping), leaving (main)", "should (main), leaving (helping)", "be (main), leaving (helping)", "All helping verbs"]', 0, 'Three verbs: "should" (modal helping), "be" (helping), "leaving" (main). Two helpers + one main = correct!', 'medium'),

('foundation', 'verbs-basics', 'beginner', 'Rearrange: completed / been / project / The / has', '["The project has been completed", "The project been has completed", "The has project been completed", "The completed has been project"]', 0, 'Pattern: subject + helping (has) + helping (been) + main (completed). Passive voice: has been + past participle.', 'medium'),

('foundation', 'verbs-basics', 'beginner', 'Choose: Which has TWO helping verbs?', '["She is singing", "I have been waiting", "They can go", "He plays"]', 1, 'Two helping verbs: "have been" waiting. Others: one helper (is, can) or no helper (plays).', 'medium'),

('foundation', 'verbs-basics', 'beginner', 'Error in: "She has finish her work."', '["Use: finished instead of finish", "Remove: has", "Use: finishing instead of finish", "Both A works"]', 0, 'Present perfect: has/have + past participle. Correct: "She has finished." Pattern: helping + past participle (not base).', 'medium'),

('foundation', 'verbs-basics', 'beginner', 'In "The food tastes good," main verb?', '["tastes", "good", "food", "No verb"]', 0, 'Main verb: "tastes" (linking verb). No helping verb. "good" = adjective. Simple present = main verb alone.', 'medium'),

-- HARD (4 questions)
('foundation', 'verbs-basics', 'beginner', 'Which is WRONG?', '["She is reading", "They have gone", "I am play", "He will come"]', 2, 'Wrong: "am play." Continuous needs -ing. Correct: "I am playing." Pattern: am/is/are + verb-ing.', 'hard'),

('foundation', 'verbs-basics', 'beginner', 'Arrange: being / is / built / The / school / new', '["The new school is being built", "The new school is build being", "The new school being is built", "The is new school being built"]', 0, 'Passive continuous: is/are + being + past participle. Pattern: subject + is + being + main verb (built). Three verbs!', 'hard'),

('foundation', 'verbs-basics', 'beginner', 'In "She might have been sleeping," identify ALL verbs:', '["might (modal), have (helping), been (helping), sleeping (main)", "might (main), sleeping (helping)", "have (main), sleeping (helping)", "All main verbs"]', 0, 'Four verbs: "might" (modal), "have" (helping), "been" (helping), "sleeping" (main). Three helpers + one main!', 'hard'),

('foundation', 'verbs-basics', 'beginner', 'Error: "They been playing for hours."', '["Add: have before been", "Remove: been", "Use: played instead of playing", "Multiple fixes work"]', 3, 'Missing helping verb. Fix: "They have been playing" (add have) OR "They were playing" (remove been, add were). Multiple fixes!', 'hard');

